_AETHERION_HEADER_ICON = 'data:image/svg+xml;base64,'
_AETHERION_WEBICON = 'data:image/svg+xml;base64,'


def _status_chip(status: str) -> str:
    normalized = "passed" if status == "passed" else "failed"
    color = "#157347" if normalized == "passed" else "#b42318"
    bg = "#e8f7ed" if normalized == "passed" else "#fdebec"
    border = "rgba(21, 115, 71, 0.28)" if normalized == "passed" else "rgba(180, 35, 24, 0.24)"
    label = "Passed" if normalized == "passed" else "Failed"
    return (
        f'<span class="status-chip" style="background:{bg};color:{color};border-color:{border};">{label}</span>'
    )


def _get_bucket_name() -> str:
    bucket_name = os.getenv("STORAGE_ACTIVITIES_BUCKET", "").strip()
    if not bucket_name:
        raise RuntimeError("STORAGE_ACTIVITIES_BUCKET is not configured.")
    return bucket_name


def _load_bytes(object_key: str) -> bytes | None:
    if not object_key:
        return None
    try:
        storage.init_client()
        if hasattr(storage, "retrieve"):
            data = storage.retrieve(
                bucket_name=_get_bucket_name(),
                object_key=object_key,
                retrieval_mode=RetrievalMode.FULL_OBJECT,
            )
            if isinstance(data, bytes):
                return data
        client = getattr(storage, "client", None)
        if client is None:
            return None
        response = client.get_object(Bucket=_get_bucket_name(), Key=object_key)
        return response["Body"].read()
    except Exception:
        return None


def _to_data_uri(object_key: str) -> str | None:
    image_bytes = _load_bytes(object_key)
    if not image_bytes:
        return None
    return f"data:image/png;base64,{base64.b64encode(image_bytes).decode('utf-8')}"


